"use client";

import * as React from "react";
import {
  OnboardingTemplate,
  Stepper,
  type StepperStep,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  CardFooter,
  Button,
  Form,
  FormField,
  FormLabel,
  FormControl,
  FormDescription,
  FormMessage,
  Input,
  Select,
  Switch,
  RadioGroup,
  RadioGroupItem,
  Label,
  Alert,
  AlertTitle,
  AlertDescription,
} from "@gunjo/ui";

/* ------------------------------------------------------------------ */
/* Wizard state                                                        */
/* ------------------------------------------------------------------ */

const STEP_LABELS = ["ようこそ", "プロフィール", "設定", "チームを招待", "完了"];

type FormState = {
  fullName: string;
  email: string;
  company: string;
  role: string;
  theme: string;
  productUpdates: boolean;
  weeklyDigest: boolean;
  invites: string[];
};

const initialForm: FormState = {
  fullName: "",
  email: "",
  company: "",
  role: "",
  theme: "system",
  productUpdates: true,
  weeklyDigest: false,
  invites: [""],
};

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/* Validation: returns a map of field -> error message (empty = valid). */
function validateProfile(form: FormState): Record<string, string> {
  const errors: Record<string, string> = {};
  if (!form.fullName.trim()) errors.fullName = "お名前を入力してください。";
  if (!form.email.trim()) errors.email = "メールアドレスを入力してください。";
  else if (!EMAIL_RE.test(form.email.trim())) errors.email = "有効なメールアドレスを入力してください。";
  if (!form.role) errors.role = "ご利用の目的を選択してください。";
  return errors;
}

/* Optional step — only validate the invites that were actually typed. */
function validateInvites(form: FormState): Record<string, string> {
  const errors: Record<string, string> = {};
  form.invites.forEach((value, i) => {
    const v = value.trim();
    if (v && !EMAIL_RE.test(v)) errors[`invite-${i}`] = "有効なメールアドレスではありません。";
  });
  return errors;
}

export default function OnboardingPage() {
  const [step, setStep] = React.useState(0);
  const [form, setForm] = React.useState<FormState>(initialForm);
  // Per-field "has the user interacted with it?" — drives whether an error is
  // shown. A field's error only appears once it's been touched (blurred) or
  // once an advance has been attempted, so the form doesn't scream on load.
  const [touchedFields, setTouchedFields] = React.useState<
    Record<string, boolean>
  >({});

  const isLast = step === STEP_LABELS.length - 1;

  const profileErrors = validateProfile(form);
  const inviteErrors = validateInvites(form);

  // Which errors are relevant to the *current* step, and is it valid?
  const currentErrors =
    step === 1 ? profileErrors : step === 3 ? inviteErrors : {};
  const currentValid = Object.keys(currentErrors).length === 0;

  // Only surface an error if its field has been touched. (Next is also gated
  // on validity, so this is purely about *when* the message text appears.)
  const visibleErrors = Object.fromEntries(
    Object.entries(currentErrors).filter(([field]) => touchedFields[field])
  );

  const markTouched = (field: string) =>
    setTouchedFields((t) => (t[field] ? t : { ...t, [field]: true }));

  const update = <K extends keyof FormState>(key: K, value: FormState[K]) =>
    setForm((f) => ({ ...f, [key]: value }));

  const stepperSteps: StepperStep[] = STEP_LABELS.map((label, i) => ({
    label,
    state: i < step ? "completed" : i === step ? "current" : "upcoming",
  }));

  const goNext = () => {
    if (!currentValid) {
      // Reveal every error on the current step on an explicit attempt.
      setTouchedFields((t) => {
        const next = { ...t };
        Object.keys(currentErrors).forEach((field) => (next[field] = true));
        return next;
      });
      return;
    }
    setStep((s) => Math.min(STEP_LABELS.length - 1, s + 1));
  };
  const goBack = () => setStep((s) => Math.max(0, s - 1));

  return (
    <OnboardingTemplate
      hero={
        <div className="flex flex-col gap-4">
          <span className="text-sm font-medium uppercase tracking-widest opacity-70">
            Acme Cloud
          </span>
          <h1 className="text-3xl font-semibold leading-tight">
            ワークスペースを準備しましょう。
          </h1>
          <p className="text-sm opacity-80">
            いくつかの簡単なステップで、すぐにご利用いただけます。設定はあとからいつでも変更できます。
          </p>
        </div>
      }
    >
      <Card>
        <CardHeader>
          {/* Stepper can overflow horizontally on narrow cards (fixed-width
              items). Wrap it so it scrolls instead of pushing the card wide. */}
          <div className="-mx-2 overflow-x-auto pb-1">
            <Stepper steps={stepperSteps} aria-label="セットアップの手順" />
          </div>
          <CardTitle>{STEP_LABELS[step]}</CardTitle>
          <CardDescription>{stepDescription(step)}</CardDescription>
        </CardHeader>

        <CardContent>
          {step === 0 && <WelcomeStep />}
          {step === 1 && (
            <ProfileStep
              form={form}
              update={update}
              errors={visibleErrors}
              onBlurField={markTouched}
            />
          )}
          {step === 2 && <PreferencesStep form={form} update={update} />}
          {step === 3 && (
            <InviteStep
              form={form}
              update={update}
              errors={visibleErrors}
              onBlurField={markTouched}
            />
          )}
          {step === 4 && <DoneStep form={form} />}
        </CardContent>

        <CardFooter>
          <Button
            variant="outline"
            onClick={goBack}
            disabled={step === 0}
            type="button"
          >
            戻る
          </Button>
          {!isLast ? (
            <Button
              onClick={goNext}
              type="button"
              // Next is disabled until the current step is valid.
              disabled={!currentValid}
            >
              {step === 3 ? "セットアップを完了" : "次へ"}
            </Button>
          ) : (
            <Button type="button" onClick={() => setStep(0)}>
              デモを最初から
            </Button>
          )}
        </CardFooter>
      </Card>
    </OnboardingTemplate>
  );
}

function stepDescription(step: number): string {
  switch (step) {
    case 0:
      return "このあと1分ほどで完了する内容をご案内します。";
    case 1:
      return "ワークスペースをあなた仕様にするため、いくつか教えてください。";
    case 2:
      return "Acme Cloud の動作をお好みに合わせて設定しましょう。";
    case 3:
      return "必要に応じてチームメンバーを招待できます。スキップしても構いません。";
    default:
      return "準備が整いました。";
  }
}

/* ------------------------------------------------------------------ */
/* Steps                                                               */
/* ------------------------------------------------------------------ */

function WelcomeStep() {
  return (
    <div className="flex flex-col gap-4 text-sm text-muted-foreground">
      <p>
        Acme Cloud へようこそ。プロフィールの作成、各種設定、そして（任意で）チームの招待を行います。
      </p>
      <ul className="ml-4 list-disc space-y-1">
        <li>プロフィールを作成</li>
        <li>お好みの設定を選択</li>
        <li>チームメンバーを招待（任意）</li>
      </ul>
    </div>
  );
}

type StepProps = {
  form: FormState;
  update: <K extends keyof FormState>(key: K, value: FormState[K]) => void;
  errors: Record<string, string>;
  onBlurField: (field: string) => void;
};

function ProfileStep({ form, update, errors, onBlurField }: StepProps) {
  return (
    <Form onSubmit={(e) => e.preventDefault()}>
      <FormField>
        <FormLabel htmlFor="fullName">氏名</FormLabel>
        <FormControl>
          <Input
            id="fullName"
            value={form.fullName}
            onChange={(e) => update("fullName", e.target.value)}
            onBlur={() => onBlurField("fullName")}
            placeholder="山田 花子"
            aria-invalid={Boolean(errors.fullName) || undefined}
            aria-describedby={errors.fullName ? "fullName-err" : undefined}
          />
        </FormControl>
        {errors.fullName && (
          <FormMessage id="fullName-err">{errors.fullName}</FormMessage>
        )}
      </FormField>

      <FormField>
        <FormLabel htmlFor="email">仕事用メールアドレス</FormLabel>
        <FormControl>
          <Input
            id="email"
            type="email"
            value={form.email}
            onChange={(e) => update("email", e.target.value)}
            onBlur={() => onBlurField("email")}
            placeholder="hanako@acme.com"
            aria-invalid={Boolean(errors.email) || undefined}
            aria-describedby={errors.email ? "email-err" : undefined}
          />
        </FormControl>
        {errors.email && <FormMessage id="email-err">{errors.email}</FormMessage>}
      </FormField>

      <FormField>
        <FormLabel htmlFor="company">会社名</FormLabel>
        <FormControl>
          <Input
            id="company"
            value={form.company}
            onChange={(e) => update("company", e.target.value)}
            placeholder="株式会社Acme（任意）"
          />
        </FormControl>
        <FormDescription>任意 — お支払いの際にのみ使用します。</FormDescription>
      </FormField>

      <FormField>
        <FormLabel htmlFor="role">Acme Cloud をどのように利用しますか？</FormLabel>
        <FormControl>
          <Select
            id="role"
            value={form.role}
            onChange={(e) => {
              update("role", e.target.value);
              onBlurField("role");
            }}
            onBlur={() => onBlurField("role")}
            aria-invalid={Boolean(errors.role) || undefined}
            aria-describedby={errors.role ? "role-err" : undefined}
          >
            <option value="" disabled>
              役割を選択…
            </option>
            <option value="developer">エンジニア</option>
            <option value="designer">デザイナー</option>
            <option value="pm">プロダクトマネージャー</option>
            <option value="other">その他</option>
          </Select>
        </FormControl>
        {errors.role && <FormMessage id="role-err">{errors.role}</FormMessage>}
      </FormField>
    </Form>
  );
}

function PreferencesStep({
  form,
  update,
}: Pick<StepProps, "form" | "update">) {
  return (
    <div className="flex flex-col gap-6">
      <fieldset className="flex flex-col gap-3">
        <legend className="mb-1 text-sm font-medium text-foreground">
          テーマ
        </legend>
        <RadioGroup
          value={form.theme}
          onValueChange={(v) => update("theme", v)}
          aria-label="テーマ"
        >
          {[
            ["system", "システムに合わせる"],
            ["light", "ライト"],
            ["dark", "ダーク"],
          ].map(([value, label]) => (
            <div key={value} className="flex items-center gap-2">
              <RadioGroupItem value={value} id={`theme-${value}`} />
              <Label htmlFor={`theme-${value}`}>{label}</Label>
            </div>
          ))}
        </RadioGroup>
      </fieldset>

      <div className="flex flex-col gap-4">
        <div className="flex items-center justify-between gap-4">
          <div className="flex flex-col">
            <Label htmlFor="productUpdates">製品アップデート</Label>
            <span className="text-xs text-muted-foreground">
              新機能に関するお知らせを、ときどきメールでお届けします。
            </span>
          </div>
          <Switch
            id="productUpdates"
            checked={form.productUpdates}
            onCheckedChange={(c) => update("productUpdates", c)}
            aria-label="製品アップデート"
          />
        </div>

        <div className="flex items-center justify-between gap-4">
          <div className="flex flex-col">
            <Label htmlFor="weeklyDigest">週次ダイジェスト</Label>
            <span className="text-xs text-muted-foreground">
              毎週月曜日に、ワークスペースの活動をまとめてお届けします。
            </span>
          </div>
          <Switch
            id="weeklyDigest"
            checked={form.weeklyDigest}
            onCheckedChange={(c) => update("weeklyDigest", c)}
            aria-label="週次ダイジェスト"
          />
        </div>
      </div>
    </div>
  );
}

function InviteStep({ form, update, errors, onBlurField }: StepProps) {
  const setInvite = (i: number, value: string) => {
    const next = [...form.invites];
    next[i] = value;
    update("invites", next);
  };
  const addInvite = () => update("invites", [...form.invites, ""]);
  const removeInvite = (i: number) =>
    update(
      "invites",
      form.invites.filter((_, idx) => idx !== i)
    );

  return (
    <div className="flex flex-col gap-4">
      <Form onSubmit={(e) => e.preventDefault()}>
        {form.invites.map((value, i) => (
          <FormField key={i}>
            <FormLabel htmlFor={`invite-${i}`}>
              メンバー {i + 1} のメールアドレス
            </FormLabel>
            <div className="flex items-start gap-2">
              <FormControl className="flex-1">
                <Input
                  id={`invite-${i}`}
                  type="email"
                  value={value}
                  onChange={(e) => setInvite(i, e.target.value)}
                  onBlur={() => onBlurField(`invite-${i}`)}
                  placeholder="member@acme.com"
                  aria-invalid={Boolean(errors[`invite-${i}`]) || undefined}
                />
              </FormControl>
              {form.invites.length > 1 && (
                <Button
                  type="button"
                  variant="outline"
                  size="icon"
                  aria-label={`メンバー ${i + 1} を削除`}
                  onClick={() => removeInvite(i)}
                >
                  ✕
                </Button>
              )}
            </div>
            {errors[`invite-${i}`] && (
              <FormMessage>{errors[`invite-${i}`]}</FormMessage>
            )}
          </FormField>
        ))}
      </Form>
      <div>
        <Button type="button" variant="ghost" onClick={addInvite}>
          ＋ 追加する
        </Button>
      </div>
    </div>
  );
}

function DoneStep({ form }: { form: FormState }) {
  const invited = form.invites.map((v) => v.trim()).filter(Boolean);
  return (
    <div className="flex flex-col gap-4">
      {/* Alert ships a hardcoded w-[320px]; override to fill the card. */}
      <Alert variant="success" className="w-full">
        <AlertTitle>準備が整いました</AlertTitle>
        <AlertDescription>
          {form.fullName || "ゲスト"}さん、ワークスペースの準備が整いました。
        </AlertDescription>
      </Alert>
      <dl className="grid grid-cols-[auto_1fr] gap-x-4 gap-y-1 text-sm">
        <dt className="text-muted-foreground">氏名</dt>
        <dd>{form.fullName}</dd>
        <dt className="text-muted-foreground">メールアドレス</dt>
        <dd>{form.email}</dd>
        <dt className="text-muted-foreground">役割</dt>
        <dd>{form.role || "—"}</dd>
        <dt className="text-muted-foreground">テーマ</dt>
        <dd className="capitalize">{form.theme}</dd>
        <dt className="text-muted-foreground">招待済み</dt>
        <dd>{invited.length ? invited.join(", ") : "まだいません"}</dd>
      </dl>
    </div>
  );
}
